/// Generated by ChatGPT (OpenAI)
use psi::client::ClientStateInit;
use psi::server::ServerStateInit;
use psi::types::Element;

use sha2::{Digest, Sha512};

use psi::threaded::run_threaded;

fn main() {
    // Run registered benchmarks.
    divan::main();
}

fn make_element(v: u8) -> Element {
  let mut hasher = Sha512::new();
  hasher.update([v]);
  let result = hasher.finalize();

  let mut e = [0u8; 64];
  e.copy_from_slice(&result);
  e
}

fn contains_elem(set: &[Element], v: u8) -> bool {
  set.contains(&make_element(v))
}

#[divan::bench]
fn psi_small_example() {
  // Server set X
  let server_set = vec![make_element(1), make_element(2), make_element(3)];

  // Client set Y
  let client_set = vec![make_element(2), make_element(3), make_element(4)];

  let server_init = ServerStateInit { X: server_set };
  let client_init = ClientStateInit { Y: client_set };

  // Run the protocol locally
  let (server1, message1) = server_init.start();
  let (client2, message2) = client_init.respond(message1);
  let (_server3, message3) = server1.respond(message2);

  let intersection = client2.complete(message3);

  // Expected intersection: {2,3}
  assert_eq!(intersection.len(), 2);
  assert!(contains_elem(&intersection, 2));
  assert!(contains_elem(&intersection, 3));
}


#[divan::bench]
fn threaded_small_example() {
  let x = vec![make_element(1), make_element(2), make_element(3)];

  let y = vec![make_element(2), make_element(3), make_element(4)];

  let intersection = run_threaded(x, y);

  // Expected intersection: {2,3}
  assert_eq!(intersection.len(), 2);
  assert!(contains_elem(&intersection, 2));
  assert!(contains_elem(&intersection, 3));
}
